  ('pukao-7c4986e7-moex-00357', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '在短期的完全競爭市場當中，假設勞工是可變動的要素投入。有關個別廠商供給曲線移動，下列敘述何 者正確？', '["勞工的工資上升時，個別廠商的供給曲線會往右邊移動", "勞工的工資上升時，個別廠商的供給曲線會往左邊移動", "勞工的工資上升時，個別廠商的供給曲線移動方向不確定", "勞工的工資上升時，個別廠商的供給曲線不會移動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00358', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '既然自由貿易對兩國皆有利，為何還有部分團體強力反對？', '["自由貿易長期受益，但短期會受害，故有反對聲浪", "自由貿易兩國受益程度不一，受益少的國家有理由反對", "自由貿易生產者受益，但消費者受害，因而反對", "自由貿易對兩個國家總體都有利，但部分產業與廠商受害，造成部分員工失業，這些人會反對"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00359', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '如果所得收入保持不變並且工資率增加，那麼工作時間將會：', '["增加", "減少", "保持不變", "不能確定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00360', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '在一完全競爭市場中，供給線為正斜率，需求線為負斜率，且廠商的生產造成外部成本。在沒有管制的情 況下，該市場的均衡價格與銷售量分別為P1與Q1，而社會最適的價格與銷售量分別為P2與Q2。下列敘 述何者正確？', '["P1>P2，Q1>Q2", "P1>P2，Q1<Q2", "P1<P2，Q1>Q2", "P1<P2，Q1<Q2"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00361', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '在一完全競爭市場，其需求函數為P=100 Q，供給函數為P=10，此處P為價格（單位為元），Q為數 量。假設所有廠商均為同質，且廠商每生產一單位產品所造成的邊際外部成本為2元。下列何者為社會最 − 適的生產量？', '["88", "89", "90", "92"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00362', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '被污染的湖邊有10棟房屋，每棟租金為20,000元。在其他類似的湖邊沒有污染的房屋，每月租金為40,000元。 湖水之所以被污染，是因為湖邊有家食品加工廠在湖中傾倒廢棄物。為了解決污染問題，加工廠可以加裝 價值150,000元的機器，並將水中的污染減少到可以忽略不計。以上敘述所涉及的外部成本的值為：', '["20,000元", "150,000元", "200,000元", "400,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00363', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '由於國家公園的遊客過多，導致生態環境惡化，野生動、植物都大量減少。為解決以上的困境，請問下列 何種方案較可能有效的解決國家公園所面臨的問題？', '["降低遊憩設施的舒適程度", "增加野生動植物的野放與種植", "提高國家公園的門票價格", "減少國家公園的管理人員以及設施維護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00364', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '需求拉動型通貨膨脹將造成：', '["物價水準提升但不改變實質GDP", "同時使物價水準及實質GDP提升", "物價水準提升但降低實質GDP", "總合供給曲線（aggregatesupplycurve）向右移動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00365', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '我國針對某進口電子產品進行研發，取得創新與國際競爭力，並開始出口該電子產品，則下列敘述何者正確？', '["創新後，我國在該電子產品的生產上一定有絕對利益", "創新後，我國在該產品的生產上一定沒有絕對利益", "創新前，我國生產該產品的機會成本一定比較高", "創新前，我國生產該產品的機會成本一定比較低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00366', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '根據總合供給與總合需求模型，下列各項景氣衝擊何者可能造成停滯性通膨？', '["技術進步", "大地震", "出口衰退", "消費者信心增強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:47+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
